import { ref, inject, provide, computed, onMounted, onUnmounted, getCurrentInstance, type ComputedRef, type InjectionKey, type Ref } from 'vue'
import { hasDocument, isClient, safeGetStorageItem, safeSetStorageItem } from '@/lib/env'

export type ThemeName = 'classic' | 'pastel' | 'mono' | 'warm'
export type ColorMode = 'light' | 'dark' | 'system'
export type ResolvedColorMode = 'light' | 'dark'

export interface UseThemeReturn {
    theme: Ref<ThemeName>
    colorMode: Ref<ColorMode>
    resolvedColorMode: ComputedRef<ResolvedColorMode>
    isSystemDark: Ref<boolean>
    setTheme: (name: ThemeName) => void
    setCustomVariable: (name: `--${string}`, value: string) => void
    removeCustomVariable: (name: `--${string}`) => void
    toggleColorMode: () => void
    applyColorMode: (mode: ColorMode) => void
    initTheme: () => void
    destroy: () => void
}

const THEME_KEY: InjectionKey<UseThemeReturn> = Symbol('brutx-theme')

// 常量定义
const VALID_THEMES: readonly ThemeName[] = ['classic', 'pastel', 'mono', 'warm'] as const
const VALID_MODES: readonly ColorMode[] = ['light', 'dark', 'system'] as const

// 类型守卫
function isValidTheme(value: string | null): value is ThemeName {
    return value !== null && (VALID_THEMES as readonly string[]).includes(value)
}

function isValidColorMode(value: string | null): value is ColorMode {
    return value !== null && (VALID_MODES as readonly string[]).includes(value)
}

function getThemeClass(name: ThemeName): string {
    return `theme-${name}`
}

export function createTheme(): UseThemeReturn {
    const theme = ref<ThemeName>('classic')
    const colorMode = ref<ColorMode>('light')
    const isSystemDark = ref(false)
    let mediaQuery: MediaQueryList | null = null
    let initialized = false

    // 计算实际应用的颜色模式
    const resolvedColorMode = computed<ResolvedColorMode>(() => {
        if (colorMode.value === 'system') {
            return isSystemDark.value ? 'dark' : 'light'
        }
        return colorMode.value
    })

    function applyTheme(name: ThemeName) {
        if (!hasDocument) return
        const root = document.documentElement
        // 移除旧主题类名（如果存在）
        if (theme.value !== name) {
            root.classList.remove(getThemeClass(theme.value))
        }
        // 添加新主题类名（检查是否已存在）
        if (!root.classList.contains(getThemeClass(name))) {
            root.classList.add(getThemeClass(name))
        }
        theme.value = name
        safeSetStorageItem('brutx-theme', name)
    }

    function applyResolvedMode(mode: ResolvedColorMode) {
        if (!hasDocument) return
        const root = document.documentElement
        if (mode === 'dark') {
            root.classList.add('dark')
        } else {
            root.classList.remove('dark')
        }
    }

    function applyColorMode(mode: ColorMode) {
        if (mode === colorMode.value) return
        colorMode.value = mode
        safeSetStorageItem('brutx-color-mode', mode)

        if (mode === 'system') {
            applyResolvedMode(isSystemDark.value ? 'dark' : 'light')
        } else {
            applyResolvedMode(mode)
        }
    }

    function toggleColorMode() {
        // Toggle only between light and dark, skip system
        const newMode: ResolvedColorMode = resolvedColorMode.value === 'light' ? 'dark' : 'light'
        applyColorMode(newMode)
    }

    function setTheme(name: ThemeName) {
        applyTheme(name)
    }

    function setCustomVariable(name: `--${string}`, value: string) {
        if (!hasDocument) return
        document.documentElement.style.setProperty(name, value)
    }

    function removeCustomVariable(name: `--${string}`) {
        if (!hasDocument) return
        document.documentElement.style.removeProperty(name)
    }

    // 监听系统暗色模式变化
    function onSystemDarkChange(e: MediaQueryListEvent) {
        isSystemDark.value = e.matches
        if (colorMode.value === 'system') {
            applyResolvedMode(e.matches ? 'dark' : 'light')
        }
    }

    function initTheme() {
        // 防止重复初始化
        if (initialized) return
        initialized = true

        // 第一步：初始化系统暗色模式检测（必须在应用颜色模式之前，isSystemDark 需先就绪）
        if (isClient) {
            mediaQuery = window.matchMedia('(prefers-color-scheme: dark)')
            isSystemDark.value = mediaQuery.matches
            mediaQuery.addEventListener('change', onSystemDarkChange)
        }

        // 第二步：应用保存的主题（复用 applyTheme，避免重复 DOM 操作与持久化逻辑）
        const savedThemeRaw = safeGetStorageItem('brutx-theme')
        const savedTheme = isValidTheme(savedThemeRaw) ? savedThemeRaw : null
        applyTheme(savedTheme ?? theme.value)

        // 第三步：应用保存的颜色模式（复用 applyColorMode，避免重复逻辑）
        const savedModeRaw = safeGetStorageItem('brutx-color-mode')
        const savedMode = isValidColorMode(savedModeRaw) ? savedModeRaw : null
        if (savedMode) {
            applyColorMode(savedMode)
        } else if (isSystemDark.value) {
            applyColorMode('system')
        }
    }

    // 清理监听器
    function destroy() {
        mediaQuery?.removeEventListener('change', onSystemDarkChange)
        mediaQuery = null
    }

    return {
        theme,
        colorMode,
        resolvedColorMode,
        isSystemDark,
        setTheme,
        setCustomVariable,
        removeCustomVariable,
        toggleColorMode,
        applyColorMode,
        initTheme,
        destroy,
    }
}

let fallbackInstance: UseThemeReturn | null = null

export function provideTheme(): UseThemeReturn {
    const theme = createTheme()
    provide(THEME_KEY, theme)

    if (getCurrentInstance()) {
        // 在挂载后初始化主题（确保 DOM 可用），与 useTheme() fallback 行为一致
        onMounted(() => theme.initTheme())
        onUnmounted(() => theme.destroy())
    }

    return theme
}

export function useTheme(): UseThemeReturn {
    const theme = inject(THEME_KEY)
    if (theme) return theme
    if (typeof console !== 'undefined') {
        console.warn('[BrutxUI] useTheme() called without provideTheme(). Falling back to shared singleton.')
    }
    if (!fallbackInstance) {
        fallbackInstance = createTheme()
        fallbackInstance.initTheme()
    }
    return fallbackInstance
}

export function destroyFallback() {
    if (fallbackInstance) {
        fallbackInstance.destroy()
        fallbackInstance = null
    }
}

if (typeof window !== 'undefined') {
    window.addEventListener('beforeunload', destroyFallback)
}

import { type ComputedRef, type InjectionKey, type MaybeRef, computed, inject, provide, unref } from 'vue'
import { zhCN } from '@/locales/zh-CN'
import type { Locale } from '@/locales/types'

export const LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Locale>> = Symbol('brutx-ui-locale')
export const FALLBACK_LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Partial<Locale>>> = Symbol('brutx-ui-fallback-locale')

export type TranslateFunction = (path: string, params?: Record<string, string | number>) => string

export interface LocaleOptions {
    locale: MaybeRef<Locale>
    fallbackLocale?: MaybeRef<Partial<Locale>>
}

export function provideLocale(localeOrOptions: MaybeRef<Locale> | LocaleOptions): void {
    // 检查是否是 LocaleOptions 格式（包含 locale 属性）
    if (
        typeof localeOrOptions === 'object' &&
        localeOrOptions !== null &&
        'locale' in localeOrOptions
    ) {
        const options = localeOrOptions as LocaleOptions
        provide(LOCALE_INJECTION_KEY, options.locale)
        if (options.fallbackLocale) {
            provide(FALLBACK_LOCALE_INJECTION_KEY, options.fallbackLocale)
        }
    } else {
        // 直接传入 MaybeRef<Locale> 格式（向后兼容）
        provide(LOCALE_INJECTION_KEY, localeOrOptions as MaybeRef<Locale>)
    }
}

function resolveByPath(obj: unknown, path: string): string | undefined {
    const keys = path.split('.')
    let result: unknown = obj
    for (const key of keys) {
        if (typeof result !== 'object' || result === null) return undefined
        result = (result as Record<string, unknown>)[key]
    }
    return typeof result === 'string' ? result : undefined
}

function interpolate(template: string, params?: Record<string, string | number>): string {
    if (!params) return template
    return Object.entries(params).reduce(
        (str, [k, v]) => str.split(`{${k}}`).join(String(v)),
        template,
    )
}

export function useLocale(): { locale: ComputedRef<Locale>; t: TranslateFunction } {
    const injected = inject<MaybeRef<Locale> | undefined>(LOCALE_INJECTION_KEY, undefined)
    const injectedFallback = inject<MaybeRef<Partial<Locale>> | undefined>(FALLBACK_LOCALE_INJECTION_KEY, undefined)

    const locale = computed<Locale>(() => {
        const resolved = injected ? unref(injected) : undefined
        return resolved ?? zhCN
    })

    const fallbackLocale = computed<Partial<Locale>>(() => {
        return injectedFallback ? unref(injectedFallback) : {}
    })

    function t(path: string, params?: Record<string, string | number>): string {
        // 1. 尝试从用户 locale 查找
        const currentVal = resolveByPath(locale.value, path)
        if (currentVal !== undefined) return interpolate(currentVal, params)

        // 2. 尝试从自定义 fallback locale 查找
        if (fallbackLocale.value && Object.keys(fallbackLocale.value).length > 0) {
            const fallbackVal = resolveByPath(fallbackLocale.value, path)
            if (fallbackVal !== undefined) return interpolate(fallbackVal, params)
        }

        // 3. 尝试从默认 zhCN 查找
        const zhCNVal = resolveByPath(zhCN, path)
        if (zhCNVal !== undefined) return interpolate(zhCNVal, params)

        // 4. 返回 path 原文
        return path
    }

    return { locale, t }
}

/**
 * Environment detection utilities for SSR compatibility.
 * Use these instead of scattered `typeof document/window` checks.
 */

/** Whether the code is running in a browser environment (not SSR). */
export const isClient = typeof window !== 'undefined'

/** Whether `document` is available. */
export const hasDocument = typeof document !== 'undefined'

/** Whether `localStorage` is available (may be blocked in Safari private mode). */
export const hasLocalStorage = typeof localStorage !== 'undefined'

/** Whether `document.body` is available for imperative mounting. */
export function canUseDocumentBody(): boolean {
    return hasDocument && document.body !== null
}

/** Whether IntersectionObserver is available. */
export const hasIntersectionObserver = isClient && typeof window.IntersectionObserver !== 'undefined'

type AudioContextConstructor = typeof AudioContext

/** Get the available AudioContext constructor, including Safari's prefixed API. */
export function getAudioContextCtor(): AudioContextConstructor | null {
    if (!isClient) return null
    return window.AudioContext
        ?? (window as Window & typeof globalThis & { webkitAudioContext?: AudioContextConstructor }).webkitAudioContext
        ?? null
}

/**
 * Safely get a value from localStorage.
 * Returns `null` if localStorage is unavailable or the key doesn't exist.
 */
export function safeGetStorageItem(key: string): string | null {
    try {
        if (!hasLocalStorage) return null
        return localStorage.getItem(key)
    } catch {
        return null
    }
}

/**
 * Safely set a value in localStorage.
 * Silently fails if localStorage is unavailable (e.g. Safari private mode, storage full).
 */
export function safeSetStorageItem(key: string, value: string): void {
    try {
        if (!hasLocalStorage) return
        localStorage.setItem(key, value)
    } catch {
        // Storage full or blocked (e.g. Safari private mode)
    }
}
